#include<bits/stdc++.h>
using namespace std;
int key[11][11][15],mp[11][11][11][11];
bool vis[11][11][(1<<14)];
int dx[4]={0,1,0,-1};
int dy[4]={1,0,-1,0};
int n,m,p,k;
void addkey(int x,int y,int q)
{
    key[x][y][++key[x][y][0]]=q;
}
int getkey(int x,int y)
{
    int ans=0;
    for(int i=1;i<=key[x][y][0];i++)
    {
        ans|=(1<<(key[x][y][i]-1));
    }
    return ans;
}
struct node
{
    int x,y,step,k;
};
void bfs()
{
    queue<node> q;
    q.push((node){1,1,0,getkey(1,1)});
    vis[1][1][getkey(1,1)]=1;
    while(!q.empty())
    {
        node t=q.front();
        q.pop();
        if(t.x==n&&t.y==m)
        {
            printf("%d",t.step);
            exit(0);
        }
        for(int i=0;i<4;i++)
        {
            node t1=(node){t.x+dx[i],t.y+dy[i],t.step+1,t.k};
            if(t1.x<1||t1.x>n||t1.y<1||t1.y>m||(mp[t.x][t.y][t1.x][t1.y]==-1)||((mp[t.x][t.y][t1.x][t1.y]&t.k)!=mp[t.x][t.y][t1.x][t1.y]))
            {
                continue;
            }
            t1.k|=getkey(t1.x,t1.y);
            if(vis[t1.x][t1.y][t1.k])
            {
                continue;
            }
            vis[t1.x][t1.y][t1.k]=1;
            q.push(t1);
        }
    }
    printf("-1");
}
int main()
{
    scanf("%d%d%d%d",&n,&m,&p,&k);
    for(int i=1;i<=k;i++)
    {
        int ax,ay,bx,by,g;
        scanf("%d%d%d%d%d",&ax,&ay,&bx,&by,&g);
        if(g==0)
        {
            mp[ax][ay][bx][by]=-1;
            mp[bx][by][ax][ay]=-1;
        }
        else
        {
            mp[ax][ay][bx][by]=(1<<(g-1));
            mp[bx][by][ax][ay]=(1<<(g-1));
        }
    }
    int s;
    scanf("%d",&s);
    for(int i=1;i<=s;i++)
    {
        int x,y,q;
        scanf("%d%d%d",&x,&y,&q);
        addkey(x,y,q);
    }
    bfs();
    return 0;
}
